#!/usr/bin/env node
/**
 * Build-time (prebuild) generator for the /authenticity page. Hashes the CURATED stable public
 * assets and emits apps/web/data/authenticity.generated.ts — the manifest a visitor's browser
 * re-verifies against the served bytes. Regenerated on every build (the gen-iac precedent), so
 * a deployed build's manifest can never drift from its own assets.
 *
 * DETERMINISTIC by design: no timestamps, no git sha — a committed generated file must not
 * dirty git on every build, and the web Docker context excludes .git. The committed copy is
 * the out-of-band anchor (cross-checkable on GitHub); the prebuild regenerates it on every
 * build, so the served manifest always matches its own assets — re-run this script and diff
 * the committed copy to check it yourself.
 *
 * Entries are {src, path}: src = where the file lives in the repo; path = the SERVED URL
 * (app/icon.svg serves at /icon.svg). A missing asset HARD-FAILS the build.
 *   node apps/web/scripts/gen-authenticity.mjs
 */
import { createHash } from "node:crypto";
import { readFileSync, writeFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const webRoot = join(here, "..");

// Curated: the stable, human-facing artifacts. Adding a file is a deliberate, reviewed choice.
const ASSETS = [
  { src: "public/Gabriel_Carvalho_Resume.pdf", path: "/Gabriel_Carvalho_Resume.pdf" },
  { src: "public/Gabriel_Carvalho_Resume.pdf.sig", path: "/Gabriel_Carvalho_Resume.pdf.sig" },
  { src: "public/resume-pubkey.spki", path: "/resume-pubkey.spki" },
  { src: "public/og.png", path: "/og.png" },
  { src: "app/icon.svg", path: "/icon.svg" },
  { src: "app/apple-icon.png", path: "/apple-icon.png" },
];

const rows = ASSETS.map(({ src, path }) => {
  let bytes;
  try {
    bytes = readFileSync(join(webRoot, src));
  } catch {
    console.error(`gen-authenticity: MISSING asset ${src} — refusing to build a false manifest`);
    process.exit(1);
  }
  const sha256 = createHash("sha256").update(bytes).digest("hex");
  return { path, sha256, bytes: bytes.length };
});

const out = `// GENERATED by scripts/gen-authenticity.mjs — do not edit by hand.
// Deterministic SHA-256 manifest of the site's stable public assets; regenerated by every
// build's prebuild, so the served copy can't drift from its own assets. The committed copy
// is the out-of-band anchor: cross-check the served /authenticity table against this file on
// GitHub, or re-run the generator and diff.

export type AuthAsset = { path: string; sha256: string; bytes: number };

export const AUTH_ASSETS: readonly AuthAsset[] = ${JSON.stringify(rows, null, 2)};

export const GENERATED_NOTE =
  "generated at build by scripts/gen-authenticity.mjs — deterministic, drift-gated";
`;

writeFileSync(join(webRoot, "data", "authenticity.generated.ts"), out);
console.log(`gen-authenticity: ${rows.length} assets hashed`);
